DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "contextForm.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ @var = random_subset(3, 'a'..'n', 'p'..'z', 'A'..'D', 'F'..'N', 'P'..'T', 'V'..'Z'); Context("Numeric")->variables->are($var[0] => 'Real', $var[1] => 'Real', $var[2] => 'Real'); $given = Formula("$var[0] $var[1] + $var[2]"); $ans = Formula("$var[1] $var[0] + $var[2]"); $evaluator = $ans->cmp(checker => sub{ my ($correct, $student, $ans) = @_; Value->Error("This is the original expression") if ($student eq $given); Value->Error("This is algebraically equivalent to the given expression, but using commutativity of multiplication would give you something else") if (($student == $correct) && ($student ne $correct)); return ($student eq $correct); });
############################################################ # Body ############################################################
BEGIN_PGML Demonstrate that you know the meanings of the various algebraic properties by applying the given algebraic property to the given expression to get a new expression.
Apply commutativity of multiplication to [`[$given]\text{.}`]
[_]{$evaluator}{16}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION There is one place in this expression where there is multiplication. To apply commutativity of multiplication, we just write those two factors in the opposite order. This gives us [`[$ans]\text{.}`]
END_PGML_SOLUTION
